import AVFoundation
import Foundation
import os

// MARK: - Audio Processing, Timers & Buffer Callbacks

extension CompositeCaptureSession {
    func startDurationTimer() {
        durationTimer = Task { [weak self] in
            while !Task.isCancelled {
                try? await Task.sleep(nanoseconds: 250_000_000)
                guard let self, !Task.isCancelled else { break }

                let currentState = sessionState.withLock { $0.state }
                if case .capturing = currentState {
                    let duration = elapsedDuration()
                    setState(.capturing(duration: duration))

                    if let maxDuration = configuration.maxDuration, duration >= maxDuration {
                        _ = try? await stopCapture()
                        break
                    }
                }
            }
        }
    }

    func startProcessingLoop() {
        processingTask = Task { [weak self] in
            while !Task.isCancelled {
                try? await Task.sleep(nanoseconds: 100_000_000)
                guard let self, !Task.isCancelled else { break }

                let currentState = sessionState.withLock { $0.state }
                if case .capturing = currentState {
                    await processBuffers()
                }
            }
        }
    }

    func processBuffers() async {
        guard let micBuffer, let systemBuffer, let writer = fileWriter else { return }

        let config = configuration
        let chunkSize = Int(config.sampleRate * 0.1) // 100ms frames

        let micSamples: [Float]
        let systemSamples: [Float]

        if config.enableSystemCapture {
            let systemFramesAvailable = await systemBuffer.count / 2
            let framesToProcess = min(systemFramesAvailable, chunkSize)
            guard framesToProcess > 0 else { return }
            systemSamples = await systemBuffer.read(count: framesToProcess * 2)
            micSamples = await micBuffer.read(count: framesToProcess)
        } else {
            micSamples = await micBuffer.read(count: chunkSize)
            systemSamples = []
            guard !micSamples.isEmpty else { return }
        }

        // Deliver raw channel buffers to delegate before mixing
        let channelBuffers = ChannelBuffers(
            micSamples: micSamples,
            systemSamples: systemSamples,
            sampleRate: stereoMixer.targetSampleRate
        )
        let preDelegate = sessionState.withLock { $0.delegate }
        preDelegate?.captureSession(self, didProduceChannelBuffers: channelBuffers)

        let stereoSamples = stereoMixer.mix(
            mic: micSamples,
            system: systemSamples,
            strategy: configuration.mixingStrategy
        )
        let pcmData = stereoMixer.convertToInt16PCM(stereoSamples)

        if config.exportRawPCM {
            let micPCM = stereoMixer.convertToInt16PCM(micSamples)
            let systemPCM = stereoMixer.convertToInt16PCM(systemSamples)
            sessionState.withLock {
                $0.micPCMFileHandle?.write(micPCM)
                $0.systemPCMFileHandle?.write(systemPCM)
            }
        }

        sessionState.withLock {
            $0.diagnostics.mixCycles += 1
            $0.diagnostics.bytesWritten += pcmData.count
        }

        do {
            try await writer.write(pcmData)
        } catch {
            let delegate = sessionState.withLock { $0.delegate }
            if let captureError = error as? CaptureError {
                delegate?.captureSession(self, didEncounterError: captureError)
            }
        }
    }

    // MARK: - Audio Buffer Callbacks

    /// Processes a single mic audio buffer from AVFoundation.
    func handleMicBuffer(_ buffer: AVAudioPCMBuffer) {
        let sampleRate = buffer.format.sampleRate
        let formatDesc =
            "\(Int(sampleRate))Hz \(buffer.format.channelCount)ch "
                + "\(buffer.format.isInterleaved ? "int" : "non-int")"

        guard let samples = AudioFormatConverter.extractMonoSamples(from: buffer) else {
            logger.warning("Mic: extractMonoSamples returned nil for \(formatDesc)")
            return
        }
        let resampled = stereoMixer.resample(samples, from: sampleRate)
        updateMicLevel(samples: resampled)
        sessionState.withLock {
            $0.diagnostics.micCallbackCount += 1
            $0.diagnostics.micSamplesTotal += resampled.count
            $0.diagnostics.micFormat = formatDesc
        }
        Task { await micBuffer?.write(resampled) }
    }

    /// Processes a single system audio buffer from Core Audio tap.
    func handleSystemBuffer(_ buffer: AVAudioPCMBuffer) {
        let reportedRate = buffer.format.sampleRate
        let channelCount = Int(buffer.format.channelCount)
        let targetRate = stereoMixer.targetSampleRate
        let formatDesc =
            "\(Int(reportedRate))Hz \(channelCount)ch "
                + "\(buffer.format.isInterleaved ? "int" : "non-int")"

        guard let samples = AudioFormatConverter.extractFloatSamples(from: buffer) else {
            logger.warning("System: extractFloatSamples returned nil for \(formatDesc)")
            return
        }

        let sysCount = sessionState.withLock { $0.diagnostics.systemCallbackCount }
        if sysCount == 0 {
            logFirstSystemCallback(buffer: buffer, samples: samples, targetRate: targetRate)
        }

        let resampled = resampleSystemAudio(samples, channelCount: channelCount, sourceRate: targetRate)

        if sysCount == 0 {
            logger.info("System audio after resample: in=\(samples.count) out=\(resampled.count)")
        }

        updateSystemLevel(samples: resampled)
        sessionState.withLock {
            $0.diagnostics.systemCallbackCount += 1
            $0.diagnostics.systemSamplesTotal += resampled.count
            $0.diagnostics.systemFormat = "\(Int(reportedRate))->\(Int(targetRate))Hz \(channelCount)ch"
        }
        Task { await systemBuffer?.write(resampled) }
    }

    private func logFirstSystemCallback(buffer: AVAudioPCMBuffer, samples: [Float], targetRate: Double) {
        let rate = buffer.format.sampleRate
        let ch = Int(buffer.format.channelCount)
        logger.info("System audio: \(rate)Hz, target=\(targetRate)Hz, \(buffer.frameLength)fr, \(ch)ch")
        logger.info("System audio detail: \(samples.count) samples")
    }

    private func resampleSystemAudio(_ samples: [Float], channelCount: Int, sourceRate: Double) -> [Float] {
        if channelCount >= 2 {
            return stereoMixer.resampleStereo(samples, from: sourceRate)
        }
        let mono = stereoMixer.resample(samples, from: sourceRate)
        return stereoMixer.interleave(left: mono, right: mono)
    }

    // MARK: - Level Metering

    func updateMicLevel(samples: [Float]) {
        guard !samples.isEmpty else { return }
        let rms = sqrt(samples.map { $0 * $0 }.reduce(0, +) / Float(samples.count))
        let peak = samples.map { abs($0) }.max() ?? 0

        let current = sessionState.withLock { $0.currentLevels }

        setLevels(AudioLevels(
            micLevel: rms,
            systemLevel: current.systemLevel,
            peakMicLevel: max(peak, current.peakMicLevel),
            peakSystemLevel: current.peakSystemLevel
        ))
    }

    func updateSystemLevel(samples: [Float]) {
        guard !samples.isEmpty else { return }
        let rms = sqrt(samples.map { $0 * $0 }.reduce(0, +) / Float(samples.count))
        let peak = samples.map { abs($0) }.max() ?? 0

        let current = sessionState.withLock { $0.currentLevels }

        setLevels(AudioLevels(
            micLevel: current.micLevel,
            systemLevel: rms,
            peakMicLevel: current.peakMicLevel,
            peakSystemLevel: max(peak, current.peakSystemLevel)
        ))
    }

    // MARK: - Mic Rate Detection

    /// Starts mic capture briefly to detect the actual sample rate after
    /// Bluetooth HFP negotiation. Waits up to 500ms for the rate to stabilize.
    func detectMicRate(config: CaptureConfiguration) async throws -> Double {
        let lowestRate = UnfairLock(config.sampleRate)

        try await micCapture.start { buffer, _ in
            let rate = buffer.format.sampleRate
            lowestRate.withLock { current in
                if rate < current { current = rate }
            }
        }

        try? await Task.sleep(nanoseconds: 500_000_000)

        let result = lowestRate.withLock { $0 }
        logger.info("Mic rate probe detected: \(result)Hz (after 500ms settling)")
        return result
    }

    // MARK: - Recording Finalization

    /// Closes the file writer and builds the recording result.
    func finalizeRecording() async throws -> RecordingResult {
        guard let writer = fileWriter else {
            throw CaptureError.storageError("No file writer available")
        }

        let detectedRate = sessionState.withLock { $0.detectedMicRate }
        let actualRate = detectedRate.map { min($0, configuration.sampleRate) }

        let checksum: String
        do {
            checksum = try await writer.close(
                actualSampleRate: actualRate,
                channels: UInt16(configuration.channels),
                bitDepth: UInt16(configuration.bitDepth)
            )
        } catch {
            setState(.failed(.storageError("Failed to close file")))
            throw error
        }

        let rawPCMURLs: [URL] = sessionState.withLock {
            $0.micPCMFileHandle?.closeFile()
            $0.micPCMFileHandle = nil
            $0.systemPCMFileHandle?.closeFile()
            $0.systemPCMFileHandle = nil
            return $0.rawPCMFileURLs
        }

        let result = buildRecordingResult(checksum: checksum, rawPCMFileURLs: rawPCMURLs)
        setState(.completed(result))

        let delegate = sessionState.withLock { $0.delegate }
        delegate?.captureSession(self, didFinishCapture: result)
        return result
    }

    private func buildRecordingResult(checksum: String, rawPCMFileURLs: [URL] = []) -> RecordingResult {
        let duration = elapsedDuration()
        let config = configuration
        let fileURL: URL = sessionState.withLock { $0.fileURL! }

        let (tracks, channelLayout): ([AudioTrack], ChannelLayout)
        switch config.mixingStrategy {
        case .separated, .multichannel:
            tracks = [
                AudioTrack(type: .mic, channel: .left, label: "Mic (Local)"),
                AudioTrack(type: .system, channel: .right, label: "System (Remote, mono-fold)"),
            ]
            channelLayout = .separatedStereo
        case .blended:
            tracks = [
                AudioTrack(type: .mic, channel: .center),
                AudioTrack(type: .system, channel: .stereo),
            ]
            channelLayout = .blended
        }

        let metadata = RecordingMetadata(
            duration: duration,
            fileURL: fileURL,
            checksum: checksum,
            isEncrypted: config.encryptor != nil,
            tracks: tracks,
            encryptionAlgorithm: config.encryptor?.algorithm,
            encryptionKeyId: config.encryptor?.keyMetadata()["keyId"],
            channelLayout: channelLayout
        )

        return RecordingResult(
            fileURL: fileURL,
            duration: duration,
            metadata: metadata,
            checksum: checksum,
            rawPCMFileURLs: rawPCMFileURLs
        )
    }
}

import Foundation

/// Represents the type of an audio track.
public enum AudioTrackType: String, Sendable, Codable {
    /// Microphone input (what the user speaks).
    case mic

    /// System audio (what the user hears).
    case system
}

/// Represents the stereo channel assignment for an audio track.
public enum AudioChannel: String, Sendable, Codable {
    /// Left stereo channel.
    case left = "L"

    /// Right stereo channel.
    case right = "R"

    /// Center (mixed into both channels).
    case center = "C"

    /// Full stereo (present in both channels).
    case stereo = "LR"
}

/// Describes an audio track within a recording.
public struct AudioTrack: Sendable, Codable, Equatable {
    /// The source type of this track.
    public let type: AudioTrackType

    /// The stereo channel this track is assigned to.
    public let channel: AudioChannel

    /// Optional human-readable label for this track (e.g. "Mic (Local)").
    public let label: String?

    private enum CodingKeys: String, CodingKey {
        case type, channel, label
    }

    public init(type: AudioTrackType, channel: AudioChannel, label: String? = nil) {
        self.type = type
        self.channel = channel
        self.label = label
    }

    public func encode(to encoder: any Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(type, forKey: .type)
        try container.encode(channel, forKey: .channel)
        try container.encodeIfPresent(label, forKey: .label)
    }

    public init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        type = try container.decode(AudioTrackType.self, forKey: .type)
        channel = try container.decode(AudioChannel.self, forKey: .channel)
        label = try container.decodeIfPresent(String.self, forKey: .label)
    }
}

/// Raw per-channel audio samples from one processing cycle (~100 ms window).
///
/// Delivered via ``AudioCaptureDelegate/captureSession(_:didProduceChannelBuffers:)``
/// before mixing and file writing. All samples are Float32, normalized to [-1.0, 1.0],
/// at the session's configured sample rate.
///
/// ``systemSamples`` is full interleaved stereo [L0, R0, L1, R1, ...]. The library
/// does not fold, downsample, or otherwise modify system audio.
public struct ChannelBuffers: Sendable {
    /// Mono microphone samples. Empty when mic capture is disabled.
    public let micSamples: [Float]

    /// Interleaved stereo system audio [L0, R0, L1, R1, ...].
    /// Empty when system capture is disabled.
    public let systemSamples: [Float]

    /// Sample rate of both arrays, in Hz.
    public let sampleRate: Double

    /// Wall-clock timestamp at the start of this buffer window.
    public let timestamp: Date

    public init(micSamples: [Float], systemSamples: [Float], sampleRate: Double, timestamp: Date = Date()) {
        self.micSamples = micSamples
        self.systemSamples = systemSamples
        self.sampleRate = sampleRate
        self.timestamp = timestamp
    }
}

/// Records the actual WAV channel layout for downstream decoders.
public enum ChannelLayout: String, Sendable, Codable {
    /// Mic mixed into both channels (legacy/blended strategy).
    case blended
    /// Ch1 (Left) = mic only, Ch2 (Right) = system audio mono-folded (L+R)/2.
    case separatedStereo
    /// Single mono channel.
    case mono
}

/// Describes the transport type of an audio device.
public enum AudioTransportType: String, Sendable, Equatable {
    case builtIn
    case bluetooth
    case bluetoothLE
    case usb
    case virtual
    case unknown
}

/// Describes an available audio source on the system.
public struct AudioSource: Sendable, Equatable, Identifiable {
    /// Unique identifier for this audio source.
    public let id: String

    /// Human-readable name of the audio source.
    public let name: String

    /// The type of audio this source provides.
    public let type: AudioTrackType

    /// Whether this is the default device for its type.
    public let isDefault: Bool

    /// The transport type of this audio device (e.g. built-in, Bluetooth).
    public let transportType: AudioTransportType?

    public init(
        id: String,
        name: String,
        type: AudioTrackType,
        isDefault: Bool,
        transportType: AudioTransportType? = nil
    ) {
        self.id = id
        self.name = name
        self.type = type
        self.isDefault = isDefault
        self.transportType = transportType
    }
}

/// Real-time audio level metering information.
public struct AudioLevels: Sendable, Equatable {
    /// Current RMS level of the microphone input (0.0 to 1.0).
    public let micLevel: Float

    /// Current RMS level of the system audio input (0.0 to 1.0).
    public let systemLevel: Float

    /// Peak level of the microphone input (0.0 to 1.0).
    public let peakMicLevel: Float

    /// Peak level of the system audio input (0.0 to 1.0).
    public let peakSystemLevel: Float

    public init(
        micLevel: Float = 0,
        systemLevel: Float = 0,
        peakMicLevel: Float = 0,
        peakSystemLevel: Float = 0
    ) {
        self.micLevel = micLevel
        self.systemLevel = systemLevel
        self.peakMicLevel = peakMicLevel
        self.peakSystemLevel = peakSystemLevel
    }

    /// Default zero levels.
    public static let zero = Self()
}

/// Real-time diagnostics for debugging the capture pipeline.
public struct CaptureSessionDiagnostics: Sendable {
    /// Number of mic audio callbacks received.
    public var micCallbackCount = 0
    /// Number of system audio callbacks received.
    public var systemCallbackCount = 0
    /// Total mic samples written to buffer.
    public var micSamplesTotal = 0
    /// Total system samples written to buffer (interleaved stereo count).
    public var systemSamplesTotal = 0
    /// Format description of last mic buffer received.
    public var micFormat = "—"
    /// Format description of last system buffer received.
    public var systemFormat = "—"
    /// Total bytes written to file.
    public var bytesWritten = 0
    /// Number of processBuffers cycles that produced output.
    public var mixCycles = 0

    public init() {}
}

@testable import AudioCaptureKit
import Foundation
import Testing

@Suite("ChannelLayout — JSON coding and backward compatibility")
struct ChannelLayoutTests {

    @Test("separatedStereo encodes and round-trips correctly")
    func separatedStereo_roundTrips() throws {
        let layout = ChannelLayout.separatedStereo
        let data = try JSONEncoder().encode(layout)
        let decoded = try JSONDecoder().decode(ChannelLayout.self, from: data)
        #expect(decoded == .separatedStereo)
    }

    @Test("Missing channelLayout in JSON defaults to blended (backward compat)")
    func missingChannelLayout_defaultsToBlended() throws {
        // Build a RecordingMetadata JSON without "channelLayout" key
        let json = """
        {
            "id": "00000000-0000-0000-0000-000000000000",
            "duration": 60.0,
            "fileURL": "file:///tmp/test.wav",
            "checksum": "abc",
            "isEncrypted": false,
            "createdAt": "2024-01-01T00:00:00Z",
            "tracks": []
        }
        """.data(using: .utf8)!

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let metadata = try decoder.decode(RecordingMetadata.self, from: json)
        #expect(metadata.channelLayout == .blended)
    }

    @Test("AudioTrack label round-trips through JSON")
    func audioTrack_label_roundTrips() throws {
        let track = AudioTrack(type: .mic, channel: .left, label: "Mic (Local)")
        let data = try JSONEncoder().encode(track)
        let decoded = try JSONDecoder().decode(AudioTrack.self, from: data)
        #expect(decoded.label == "Mic (Local)")
    }

    @Test("AudioTrack nil label is omitted from JSON output")
    func audioTrack_nilLabel_omittedFromJSON() throws {
        let track = AudioTrack(type: .mic, channel: .left)
        let data = try JSONEncoder().encode(track)
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        #expect(json?["label"] == nil)
    }

    @Test("ChannelBuffers is constructible with empty arrays")
    func channelBuffers_emptyArraysAreValid() {
        let buffers = ChannelBuffers(micSamples: [], systemSamples: [], sampleRate: 48000)
        #expect(buffers.micSamples.isEmpty)
        #expect(buffers.systemSamples.isEmpty)
    }

    @Test("ChannelBuffers systemSamples count is even (interleaved stereo contract)")
    func channelBuffers_systemSamples_isFullStereo() {
        let system: [Float] = [0.1, 0.2, 0.3, 0.4] // 2 stereo frames
        let buffers = ChannelBuffers(micSamples: [], systemSamples: system, sampleRate: 48000)
        #expect(buffers.systemSamples.count % 2 == 0)
    }
}

@testable import AudioCaptureKit
import Foundation
import Testing

@Suite("RecordingMetadata Tests")
struct RecordingMetadataTests {

    @Test("Codable round-trip encode and decode")
    func codableRoundTrip() throws {
        let fileURL = URL(fileURLWithPath: "/tmp/recordings/test.enc.wav")
        let id = UUID()
        let createdAt = Date()

        let original = RecordingMetadata(
            id: id, duration: 3600.5, fileURL: fileURL,
            checksum: "a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2",
            isEncrypted: true, createdAt: createdAt,
            tracks: [
                AudioTrack(type: .mic, channel: .left),
                AudioTrack(type: .system, channel: .right),
            ],
            encryptionAlgorithm: "AES-256-GCM",
            encryptionKeyId: "key-001"
        )

        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(original)

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let decoded = try decoder.decode(RecordingMetadata.self, from: data)

        #expect(decoded.id == original.id)
        #expect(decoded.duration == original.duration)
        #expect(decoded.fileURL == original.fileURL)
        #expect(decoded.checksum == original.checksum)
        #expect(decoded.isEncrypted == original.isEncrypted)
        #expect(decoded.tracks == original.tracks)
        #expect(decoded.encryptionAlgorithm == original.encryptionAlgorithm)
        #expect(decoded.encryptionKeyId == original.encryptionKeyId)
    }

    @Test("Codable round-trip without encryption fields")
    func codableRoundTripNoEncryption() throws {
        let original = RecordingMetadata(
            duration: 120.0,
            fileURL: URL(fileURLWithPath: "/tmp/test.wav"),
            checksum: "abcdef1234567890",
            isEncrypted: false,
            tracks: [AudioTrack(type: .mic, channel: .left)]
        )

        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(original)

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let decoded = try decoder.decode(RecordingMetadata.self, from: data)

        #expect(decoded.isEncrypted == false)
        #expect(decoded.encryptionAlgorithm == nil)
        #expect(decoded.encryptionKeyId == nil)
    }

    @Test("Metadata equality")
    func metadataEquality() {
        let id = UUID()
        let url = URL(fileURLWithPath: "/tmp/test.wav")
        let date = Date()

        let meta1 = RecordingMetadata(
            id: id, duration: 60, fileURL: url, checksum: "abc",
            isEncrypted: false, createdAt: date,
            tracks: [AudioTrack(type: .mic, channel: .left)]
        )
        let meta2 = RecordingMetadata(
            id: id, duration: 60, fileURL: url, checksum: "abc",
            isEncrypted: false, createdAt: date,
            tracks: [AudioTrack(type: .mic, channel: .left)]
        )
        #expect(meta1 == meta2)
    }

    @Test("AudioTrack Codable round-trip")
    func audioTrackCodable() throws {
        let track = AudioTrack(type: .mic, channel: .left)
        let data = try JSONEncoder().encode(track)
        let decoded = try JSONDecoder().decode(AudioTrack.self, from: data)
        #expect(decoded.type == .mic)
        #expect(decoded.channel == .left)
    }

    @Test("AudioTrack channel values match schema")
    func audioTrackChannelValues() {
        #expect(AudioChannel.left.rawValue == "L")
        #expect(AudioChannel.right.rawValue == "R")
    }

    @Test("AudioTrackType values match schema")
    func audioTrackTypeValues() {
        #expect(AudioTrackType.mic.rawValue == "mic")
        #expect(AudioTrackType.system.rawValue == "system")
    }

    @Test("JSON output contains expected keys")
    func jsonContainsExpectedKeys() throws {
        let metadata = RecordingMetadata(
            duration: 30,
            fileURL: URL(fileURLWithPath: "/tmp/test.wav"),
            checksum: "abc123",
            isEncrypted: true,
            tracks: [],
            encryptionAlgorithm: "AES-256-GCM",
            encryptionKeyId: "key-1"
        )

        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(metadata)
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]

        #expect(json?["id"] != nil)
        #expect(json?["duration"] as? Double == 30)
        #expect(json?["checksum"] as? String == "abc123")
        #expect(json?["isEncrypted"] as? Bool == true)
        #expect(json?["encryptionAlgorithm"] as? String == "AES-256-GCM")
        #expect(json?["encryptionKeyId"] as? String == "key-1")
    }

    @Test("channelLayout separatedStereo serializes correctly")
    func channelLayout_separatedStereo_serializesCorrectly() throws {
        let metadata = RecordingMetadata(
            duration: 30,
            fileURL: URL(fileURLWithPath: "/tmp/test.wav"),
            checksum: "abc",
            isEncrypted: false,
            tracks: [],
            channelLayout: .separatedStereo
        )
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(metadata)
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        #expect(json?["channelLayout"] as? String == "separatedStereo")
    }

    @Test("Missing channelLayout in legacy JSON defaults to blended")
    func channelLayout_missingFromJSON_defaultsToBlended() throws {
        let json = """
        {
            "id": "00000000-0000-0000-0000-000000000000",
            "duration": 60.0,
            "fileURL": "file:///tmp/test.wav",
            "checksum": "abc",
            "isEncrypted": false,
            "createdAt": "2024-01-01T00:00:00Z",
            "tracks": []
        }
        """.data(using: .utf8)!
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let metadata = try decoder.decode(RecordingMetadata.self, from: json)
        #expect(metadata.channelLayout == .blended)
    }

    @Test("AudioTrack label is included in JSON when present")
    func audioTrack_labelIncludedInJSON_whenPresent() throws {
        let track = AudioTrack(type: .mic, channel: .left, label: "Mic (Local)")
        let data = try JSONEncoder().encode(track)
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        #expect(json?["label"] as? String == "Mic (Local)")
    }

    @Test("rawPCMFileURLs is empty by default in RecordingResult")
    func rawPCMFileURLs_emptyByDefault() {
        let result = RecordingResult(
            fileURL: URL(fileURLWithPath: "/tmp/test.wav"),
            duration: 30,
            metadata: RecordingMetadata(
                duration: 30,
                fileURL: URL(fileURLWithPath: "/tmp/test.wav"),
                checksum: "abc",
                isEncrypted: false,
                tracks: []
            ),
            checksum: "abc"
        )
        #expect(result.rawPCMFileURLs.isEmpty)
    }
}

