            stereo[i * 2] = if i < mic_frames { mic[i] } else { 0.0 }; // Left = mic
            let sys_l = if i * 2 < system.len() { system[i * 2] } else { 0.0 };
            let sys_r = if i * 2 + 1 < system.len() { system[i * 2 + 1] } else { 0.0 };
            stereo[i * 2 + 1] = (sys_l + sys_r) / 2.0; // Right = mono-fold
        }
        stereo
    }
}

